class Solution:
    def summaryRanges(self, nums: List[int]) -> List[str]:
        if not nums:
            return []

        result = []
        bottom = nums[0]
        next_val = nums[0]

        for i in range(1, len(nums)):
            val = nums[i]

            if next_val + 1 == val:
                next_val = val
            else:
                if next_val == bottom:
                    result.append(str(bottom))
                else:
                    result.append(f"{bottom}->{next_val}")

                next_val = val
                bottom = val

        if next_val == bottom:
            result.append(str(bottom))
        else:
            result.append(f"{bottom}->{next_val}")

        return result
